const { Configuration, OpenAIApi } = require('openai');

// Create configuration instance from your environment variable (not included in this snippet)
const configuration = new Configuration({
  apiKey: process.env.OPENAI_API_KEY,
});

// Initialize openai with your config
const openai = new OpenAIApi(configuration);

async function generateCode(prompt) {
  const response = await openai.createCompletion({
    model: "text-davinci-002", // you can change this to any OpenAI's model, such as GPT4
    prompt: prompt,
    max_tokens: 1000, // maximum number of tokens in the response
    temperature: 0.7, // a higher value means the result will be more random and unpredictable
  });
  
  return response.data.choices[0].text;
}